using System;

class Program
{
    static void Main()
    {
        int x = 10, y = 20;

        // Simple ternary
        int max = (x > y) ? x : y;
        Console.WriteLine($"Max: {max}");

        // Ternary in string interpolation
        int score = 75;
        Console.WriteLine($"Result: { (score >= 60 ? "Pass" : "Fail") }");

        // Null coalescing
        string? userInput = null;
        string result = userInput ?? "No input provided";
        Console.WriteLine(result);
    }
}
